import React, { useState } from "react";
import { ReactComponent as BoliviaSVG } from "../assets/boliviaMap.svg"; // Asegúrate de tener este SVG

const departamentos = [
  "La Paz", "Cochabamba", "Santa Cruz", "Oruro", "Potosí", "Chuquisaca", "Tarija", "Beni", "Pando",
];

const mapaBolivia = () => {
  const [departamentoSeleccionado, setDepartamentoSeleccionado] = useState("Selecciona un departamento");

  const manejarClick = (nombre) => {
    setDepartamentoSeleccionado(nombre);
  };

  return (
    <div className="w-full flex justify-center items-start gap-8 px-8 py-10">
      {/* Sección de textos verticales */}
      <div className="flex flex-col items-center">
        <div className="text-5xl font-bold tracking-widest rotate-180 writing-vertical-ltr text-black">
          BOLIVIA
        </div>
      </div>

      <div className="flex flex-col items-center gap-6">
        <div className="text-4xl font-semibold writing-vertical-ltr text-black">
          {departamentoSeleccionado.toUpperCase()}
        </div>
        <div className="w-64 h-40 bg-gray-100 border border-black p-4 text-sm text-gray-700 shadow-inner">
          <p>
            Aquí irá la descripción del departamento seleccionado. Esto se puede reemplazar con contenido dinámico más adelante.
          </p>
        </div>
      </div>

      {/* Mapa SVG Interactivo */}
      <div className="w-[40vw]">
        <BoliviaSVG
          className="w-full h-auto cursor-pointer"
          onClick={(e) => {
            const nombre = e.target.getAttribute("data-nombre");
            if (nombre) manejarClick(nombre);
          }}
        />
      </div>
    </div>
  );
};

export default mapaBolivia;
